var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>때리지 마, 때리지 말아 주세요, 때리지…… 끄아아아악!!</color>","JPN":"<color=#ffd34c>やめてくだ……やめてください、このとおりです……ぐわああああっ！！</color>","ENG":"<color=#ffd34c>Stop hitting me, stop hitting me, please stop hit… Aaack!!</color>","TWN":"<color=#ffd34c>別打我，拜託別打我，別打……啊啊啊！！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사, 사람 살려……! 그냥 사채업자라고 했잖아……!! 얘기가 다르다고!</color>","JPN":"<color=#ffd34c>た、助けてくれ！　ただの闇金業者と言ってたじゃないか……！！　話が違うぞ！</color>","ENG":"<color=#ffd34c>H-help!!! This was supposed to be just a loan shark!! Not some monster!</color>","TWN":"<color=#ffd34c>救…救命……！你不說你只是個放高利貸的嗎……！騙人！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지원! 지원이 필요해! 있는 놈들은 전부 불러!!</color>","JPN":"<color=#ffd34c>応援！　応援が必要だ！　待機中のやつを全員集めろ！</color>","ENG":"<color=#ffd34c>Backup! We need back up now! Call in everyone!</color>","TWN":"<color=#ffd34c>支援！需要支援！有多少人都給我叫來！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"적대 개체가 감지되지 않습니다. 상담 상태를 해제합니다.","JPN":"敵対個体が残っていないことを確認。相談状態を解除します。","ENG":"Hostility no longer detected. Disengaging interrogation mode.","TWN":"沒有感應到敵對個體，解除諮詢狀態。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"커뮤니케이션 재개 전에, 협력사와의 통신을 시도합니다.","JPN":"コミュニケーションを再開する前に、協力会社との通信を試みます。","ENG":"Attempting to contact partner firm prior to reengaging.","TWN":"在重啟溝通前，先和合作公司聯絡。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"뭡니까. 당신은.","JPN":"誰ですか、あなたは。","ENG":"Who are you? Identify yourself.","TWN":"你是誰？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"떠돌이 연주자, 셰나랍니다.","JPN":"さすらいの演奏者、シェナです。","ENG":"Oh, I'm just a wondering troubadour, Shena.","TWN":"浪人演奏家 世娜！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"무식하게 힘만 센 줄 알았더니 재빠르기까지 하네.","JPN":"バカみたいに力だけ強いと思ったら素早いじゃない。","ENG":"I thought you were just a strong brute, but you're quick on your feet too.","TWN":"我還以為你頭腦簡單空有蠻力，沒想到手腳也滿俐落的嘛～"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"좀 귀엽다, 너. 이 벌레들이랑 같이 죽여 버리려고 했는데.","JPN":"あなた、ちょっとかわいいわね。この虫けらどもと一緒に殺そうとしたんだけど。","ENG":"I kind of like you. And to think I was about to smash you with the rest of these worms.","TWN":"有點可愛，本來是想送你和這些蟲子一起上西天的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……무력화된 적대 개체들의 생명 반응 소멸. 이들과 적대 관계입니까.","JPN":"……無力化した敵性個体の生命反応消滅。彼らとは敵対関係ですか。","ENG":"…No vital signs detected in neutralized hostiles. Were these men your enemies?","TWN":"……昏厥的敵對個體生命跡象消失。你和他們不是一夥的嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"질문하는 것 좀 봐. 멍청해서 더 귀엽네.","JPN":"何そのバカみたいな質問は。それもかわいいけど。","ENG":"Aww, you little dum-dum with your stupid questions! You're so cute I could just eat you up!","TWN":"你聽聽你問的問題，真是傻到可愛呢～"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너 어디서 생산된 로봇이야? 나도 너랑 같은 기종으로 하나 구입할 수 있을까?","JPN":"あなたはどこで生産されたロボットなの？　私もあなたと同じ機種が一台ほしいわ。","ENG":"So where do they manufacture robots like you? Think I could buy one?","TWN":"你是哪裡生產的機器人？我也可以買個和你一樣的機種嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"대답하십시오.","JPN":"答えてください。","ENG":"You have not answered my question.","TWN":"請回答我。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 알짜배기 재미만 빼먹을 생각이었는데, 진짜가 여기 있었네.","JPN":"フフ、あまり期待してなかったけど、面白い子だったのね。","ENG":"Heh. I was almost getting bored with all of this 'til you showed up.","TWN":"呵呵～原本只是想來找點樂子，沒想到你真的在這裡。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"묵비권을 행사하겠다면, 물리적인 설득을 시도하겠습니다.","JPN":"黙秘権を行使するなら、物理的な説得を試みます。","ENG":"Refusal to comply will be met with kinetic persuasion.","TWN":"若你要行使緘默權，那我只好用力量說服你。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"저런, 시작하자마자 클라이맥스로 치닫는 곡은 연주하기 심심하잖아.","JPN":"あら、始まったばかりなのにクライマックスに向う曲は、演奏する側がつまらないじゃない。","ENG":"Oh my. It's no fun playing a piece that starts with the climax.","TWN":"真是的，沒有超潮迭起的曲子，演奏起來不是很無趣嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};